import { getTeamLogo } from './constants'
import type { Game, LiveScore, TeamStats } from './types'

const ESPN_BASE = 'https://site.api.espn.com/apis/site/v2/sports'

interface ESPNEvent {
  id: string
  date: string
  status: {
    type: { state: string; completed: boolean; description: string }
    period: number
    displayClock: string
  }
  competitions: Array<{
    competitors: Array<{
      homeAway: 'home' | 'away'
      team: { displayName: string; shortDisplayName: string; abbreviation: string; logo?: string }
      score?: string
      records?: Array<{ summary: string; type: string }>
    }>
    odds?: Array<{ overUnder: number; details: string }>
  }>
}

interface ESPNScoreboard {
  events: ESPNEvent[]
}

function parseESPNEvent(event: ESPNEvent, league: string): Game {
  const comp = event.competitions[0]
  const awayComp = comp.competitors.find((c) => c.homeAway === 'away')!
  const homeComp = comp.competitors.find((c) => c.homeAway === 'home')!

  const awayTeam = awayComp.team.shortDisplayName || awayComp.team.displayName
  const homeTeam = homeComp.team.shortDisplayName || homeComp.team.displayName

  const awayRecord = awayComp.records?.find((r) => r.type === 'total')?.summary || ''
  const homeRecord = homeComp.records?.find((r) => r.type === 'total')?.summary || ''

  const gameTime = new Date(event.date).toLocaleTimeString('en-US', {
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
    timeZone: 'America/New_York',
  })

  const line = comp.odds?.[0]?.overUnder || null

  return {
    id: parseInt(event.id),
    league,
    date: event.date.split('T')[0],
    away_team: awayTeam,
    home_team: homeTeam,
    away_logo: awayComp.team.logo || getTeamLogo(awayTeam, league),
    home_logo: homeComp.team.logo || getTeamLogo(homeTeam, league),
    away_record: awayRecord,
    home_record: homeRecord,
    game_time: gameTime,
    line,
    projected_total: null,
    edge: null,
    direction: null,
    is_qualified: false,
  }
}

export async function fetchESPNScoreboard(league: string, dateStr?: string): Promise<Game[]> {
  const sportPath = {
    NBA: 'basketball/nba',
    CBB: 'basketball/mens-college-basketball',
    NFL: 'football/nfl',
    CFB: 'football/college-football',
    NHL: 'hockey/nhl',
  }[league]

  if (!sportPath) return []

  const date = dateStr || new Date().toISOString().split('T')[0].replace(/-/g, '')
  const url = `${ESPN_BASE}/${sportPath}/scoreboard?dates=${date}`

  try {
    const res = await fetch(url, { next: { revalidate: 60 } })
    if (!res.ok) throw new Error(`ESPN API error: ${res.status}`)

    const data: ESPNScoreboard = await res.json()
    return data.events.map((e) => parseESPNEvent(e, league))
  } catch (err) {
    console.error(`ESPN fetch error for ${league}:`, err)
    return []
  }
}

export async function fetchLiveScores(league: string): Promise<Record<string, LiveScore>> {
  const sportPath = {
    NBA: 'basketball/nba',
    CBB: 'basketball/mens-college-basketball',
    NFL: 'football/nfl',
    CFB: 'football/college-football',
    NHL: 'hockey/nhl',
  }[league]

  if (!sportPath) return {}

  const url = `${ESPN_BASE}/${sportPath}/scoreboard`

  try {
    const res = await fetch(url, { cache: 'no-store' })
    if (!res.ok) return {}

    const data: ESPNScoreboard = await res.json()
    const scores: Record<string, LiveScore> = {}

    for (const event of data.events) {
      const comp = event.competitions[0]
      const awayComp = comp.competitors.find((c) => c.homeAway === 'away')!
      const homeComp = comp.competitors.find((c) => c.homeAway === 'home')!

      const awayTeam = awayComp.team.shortDisplayName || awayComp.team.displayName
      const homeTeam = homeComp.team.shortDisplayName || homeComp.team.displayName
      const key = `${awayTeam}@${homeTeam}`

      const status = event.status.type
      if (status.state === 'in' || status.completed) {
        scores[key] = {
          away_score: parseInt(awayComp.score || '0'),
          home_score: parseInt(homeComp.score || '0'),
          period: `Q${event.status.period}`,
          clock: event.status.displayClock,
          status: status.description,
          is_final: status.completed,
        }
      }
    }

    return scores
  } catch (err) {
    console.error(`Live scores error for ${league}:`, err)
    return {}
  }
}

export async function fetchTeamStats(teamName: string, league: string): Promise<TeamStats | null> {
  try {
    const sportPath = {
      NBA: 'basketball/nba',
      CBB: 'basketball/mens-college-basketball',
      NFL: 'football/nfl',
      CFB: 'football/college-football',
      NHL: 'hockey/nhl',
    }[league]

    if (!sportPath) return null

    const searchUrl = `${ESPN_BASE}/${sportPath}/teams?limit=500`
    const res = await fetch(searchUrl, { next: { revalidate: 86400 } })
    if (!res.ok) return null

    const data = await res.json()
    const teams = data.sports?.[0]?.leagues?.[0]?.teams || []

    const teamEntry = teams.find((t: { team: { displayName: string; shortDisplayName: string } }) => {
      const name = t.team.displayName.toLowerCase()
      const short = t.team.shortDisplayName?.toLowerCase() || ''
      return name.includes(teamName.toLowerCase()) || short.includes(teamName.toLowerCase())
    })

    if (!teamEntry) return null

    const teamId = teamEntry.team.id
    const statsUrl = `${ESPN_BASE}/${sportPath}/teams/${teamId}/statistics`
    const statsRes = await fetch(statsUrl, { next: { revalidate: 3600 } })

    if (!statsRes.ok) return null

    const statsData = await statsRes.json()
    const splits = statsData.splits?.categories || []

    let ppg = 0
    let opp_ppg = 0

    for (const cat of splits) {
      for (const stat of cat.stats || []) {
        if (stat.name === 'avgPoints' || stat.name === 'pointsPerGame') {
          ppg = parseFloat(stat.value) || 0
        }
        if (stat.name === 'avgPointsAgainst' || stat.name === 'opposingPointsPerGame') {
          opp_ppg = parseFloat(stat.value) || 0
        }
      }
    }

    return {
      ppg,
      opp_ppg,
      record: teamEntry.team.record?.items?.[0]?.summary,
    }
  } catch (err) {
    console.error(`Team stats error for ${teamName}:`, err)
    return null
  }
}
